INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('92a5851320436ba4', 'KY', '["federal","state","county"]', 'ballot_access', 'What is the primary election system in Kentucky?', '["Are Kentucky primaries open or closed?","Can unaffiliated voters participate in the Kentucky primary?","Kentucky primary voting rules"]', 'Kentucky has a strictly closed primary system. Voters must be registered as a member of the Democratic or Republican party to vote in that respective party''s primary election. Unaffiliated or independent voters cannot participate in partisan primary elections.', 'https://elect.ky.gov/', 'Kentucky State Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'All voters and candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('669c89e8e4e4efe0', 'KY', '["federal","state","county"]', 'voter_interaction', 'What is the party change deadline for Kentucky primary elections?', '["When do I have to switch parties to vote in the KY primary?","Kentucky party registration deadline","December 31 party switch deadline Kentucky"]', 'Under Kentucky law, voters who wish to change their political party affiliation and vote in the new party''s primary must do so by December 31 of the year prior to the primary. For the May 2026 primary, voters must be registered with their chosen party by December 31, 2025.', 'https://elect.ky.gov/Voters/Pages/Voter-Registration.aspx', 'Kentucky State Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('b89ac815fd17b281', 'KY', '["federal","state","county"]', 'ballot_access', 'Are write-in candidates permitted in Kentucky?', '["Do write-in votes count in KY?","How to register as a write-in candidate in Kentucky","Write-in filing deadline Kentucky 2026"]', 'Write-in candidates are not permitted in primary elections. In general elections, write-in votes are only counted if the candidate has filed a formal declaration of intent to be a write-in candidate by the statutory deadline, which for 2026 is August 24, 2026.', 'https://elect.ky.gov/Candidates/Pages/Qualifications-and-Filing-Fees.aspx', 'Kentucky State Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Write-in candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('b76fd304054ee7b9', 'KY', '["federal","state","county"]', 'filing_requirements', 'What is the candidate filing deadline for Kentucky in 2026?', '["When do candidates file for office in Kentucky?","Kentucky filing deadline 2026","January filing deadline KY"]', 'For candidates seeking a major party nomination in the 2026 primary election, the filing deadline is the first Friday following the first Monday in January. For the 2026 cycle, this deadline was January 9, 2026.', 'https://elect.ky.gov/Candidates/Pages/default.aspx', 'Kentucky State Board of Elections', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('06dd3123630d5111', 'KY', '["federal","state"]', 'ballot_access', 'What is the petition signature threshold for independent candidates in Kentucky?', '["Independent candidate ballot access Kentucky","Running without a party in KY 2026","How many signatures for independent US Senate KY"]', 'Independent candidates must submit a petition of nomination. Under KRS 118.315, candidates for statewide office (like U.S. Senate) need 5,000 valid signatures from registered voters. Candidates for U.S. Congress or other district offices require 400 signatures. State legislature requires 100 signatures. The deadline to file is the first Tuesday in June.', 'https://apps.legislature.ky.gov/law/statutes/statute.aspx?id=43831', 'Kentucky Revised Statutes 118.315', '2026-05-17', 'static', 'statute_citation', 'Independent candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('d574b189183a022a', 'KY', '["federal","state","county"]', 'ballot_access', 'Does Kentucky have a sore loser law?', '["Can I run as an independent if I lose the KY primary?","Kentucky sore loser statute","General election ballot access after primary defeat KY"]', 'Yes. Kentucky strictly enforces a sore loser law under KRS 118.345. A candidate who runs in a party''s primary and is defeated cannot subsequently file as an independent candidate or a write-in candidate for the same office in that year''s general election.', 'https://apps.legislature.ky.gov/law/statutes/statute.aspx?id=27521', 'Kentucky Revised Statutes 118.345', '2026-05-17', 'static', 'statute_citation', 'Major party candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('dea7aa8f21fe33e9', 'KY', '["state"]', 'ballot_access', 'Do the Governor and Lieutenant Governor run on a joint ticket in Kentucky?', '["Kentucky joint ticket rules","How are Lt Gov candidates selected in KY?","Does the Governor pick a running mate in Kentucky?"]', 'Yes. Following a 1992 constitutional amendment, the Governor and Lieutenant Governor of Kentucky run on a joint ticket (a single slate) in both the primary and general elections. The gubernatorial candidate selects their Lieutenant Governor running mate prior to filing.', 'https://elect.ky.gov/Candidates/Pages/Qualifications-and-Filing-Fees.aspx', 'Kentucky State Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('95c555e64f63f827', 'KY', '["federal","state","county"]', 'election_dates', 'When are the primary and general elections in Kentucky for 2026?', '["Kentucky primary date 2026","When is Election Day 2026 in Kentucky?","May primary Kentucky"]', 'The Kentucky primary election will be held on Tuesday, May 19, 2026. Plurality wins, meaning there are no primary runoffs. The general election will be held on Tuesday, November 3, 2026. Polls are open from 6:00 a.m. to 6:00 p.m. local time.', 'https://elect.ky.gov/Voters/Pages/Election-Calendar.aspx', 'Kentucky State Board of Elections', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('0c8b77bbd8a82270', 'KY', '["state"]', 'election_dates', 'Is Governor Andy Beshear running for re-election in 2026?', '["Kentucky Governor election 2026","Who is defending the KY Governor seat?","Is Andy Beshear on the 2026 ballot?"]', 'No. Kentucky elects its Governor and all statewide executive officers entirely on odd-year election cycles. Governor Andy Beshear (D) was re-elected in 2023, and his second term runs through late 2027. There is no gubernatorial race on the 2026 midterm ballot.', 'https://elect.ky.gov/', 'Kentucky State Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('4b889ad6ad75bbd3', 'KY', '["federal"]', 'election_dates', 'Which U.S. Senate seat is up for election in Kentucky in 2026?', '["Is Mitch McConnell up for re-election in 2026?","Kentucky US Senate cycle 2026","Open Senate seat Kentucky 2026"]', 'The Class 2 U.S. Senate seat is up for election in 2026. It is a major open-seat race, as incumbent Mitch McConnell (R) announced he is not seeking re-election. Senator Rand Paul (Class 3) was re-elected in 2022 and will not appear on the ballot again until 2028.', 'https://www.senate.gov/senators/Class_II.htm', 'U.S. Senate - Class II Senators', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('0b7f5cb61b7ba694', 'KY', '["federal"]', 'election_dates', 'Is Senator Rand Paul up for re-election in 2026?', '["When is Rand Paul''s next election?","Kentucky Class 3 Senate election","Is Rand Paul on the 2026 ballot?"]', 'No. Senator Rand Paul holds the Class 3 U.S. Senate seat for Kentucky. He was re-elected in 2022 and his current term runs until January 2029, meaning he will not be on the 2026 ballot.', 'https://www.senate.gov/senators/Class_III.htm', 'U.S. Senate - Class III Senators', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('ce05d75e98126353', 'KY', '["federal"]', 'election_dates', 'How many U.S. House districts are in Kentucky for the 2026 election?', '["Kentucky congressional apportionment","Are all KY congressional seats up in 2026?","Number of US Representatives from Kentucky"]', 'Kentucky is apportioned 6 U.S. House districts. All six seats are on the 2026 ballot, as U.S. Representatives serve two-year terms.', 'https://elect.ky.gov/', 'Kentucky State Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('5eca1bb43f552ece', 'KY', '["state"]', 'election_dates', 'Which Kentucky State Legislature seats are up for election in 2026?', '["Are all Kentucky House seats up in 2026?","Kentucky Senate election cycle 2026","Which legislative districts are on the ballot in KY?"]', 'All 100 seats in the Kentucky House of Representatives (2-year terms) are up for election in 2026. The Kentucky State Senate has 38 members serving staggered 4-year terms; in 2026, the 19 even-numbered districts are on the ballot.', 'https://legislature.ky.gov/', 'Kentucky General Assembly', '2026-05-17', 'per_cycle', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('b8a6ab721f8b6486', 'KY', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in Kentucky in 2026?', '["Is the Attorney General up in 2026?","KY statewide election list 2026","When is the Secretary of State election in KY?"]', 'None. Kentucky elects ALL of its statewide executive officers (including Governor, Lieutenant Governor, Attorney General, Secretary of State, Treasurer, and Auditor) concurrently on an odd-year election cycle (e.g., 2023, 2027). There are no statewide executive races on the 2026 midterm ballot.', 'https://elect.ky.gov/', 'Kentucky State Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('922c599df445dd1c', 'KY', '["judicial"]', 'election_dates', 'How are Kentucky Supreme Court justices selected and are they on the ballot?', '["Kentucky judicial elections 2026","Are KY judges elected or appointed?","Nonpartisan judicial elections Kentucky"]', 'Kentucky Supreme Court justices are elected in nonpartisan elections from seven supreme court districts. They serve eight-year staggered terms. Justices face standard competitive nonpartisan elections during the regular primary and general election cycles rather than retention ''Yes/No'' votes.', 'https://kycourts.gov/Courts/Supreme-Court/Pages/default.aspx', 'Kentucky Court of Justice', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('2d1246933ea9574f', 'KY', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Governor of Kentucky?', '["Age and residency for Kentucky Governor","Kentucky Constitution Governor qualifications","Who is eligible to be Governor of KY?"]', 'Under the Kentucky Constitution, a candidate for Governor must be at least 30 years of age, and must have been a citizen and resident of Kentucky for at least six years continuously preceding their election.', 'https://elect.ky.gov/Candidates/Pages/Qualifications-and-Filing-Fees.aspx', 'Kentucky State Board of Elections - Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'Gubernatorial candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('22cffea3237e3f1c', 'KY', '["state"]', 'candidate_eligibility', 'What are the qualifications and term limits for the Kentucky State Legislature?', '["Qualifications for KY State Representative","Age requirement Kentucky State Senate","Kentucky legislature term limit status"]', 'A candidate for the State Senate must be at least 30 years old, a KY resident for 6 years, and a district resident for 1 year. A State House candidate must be at least 24 years old, a KY resident for 2 years, and a district resident for 1 year. Kentucky does NOT impose term limits on state legislators.', 'https://elect.ky.gov/Candidates/Pages/Qualifications-and-Filing-Fees.aspx', 'Kentucky State Board of Elections - Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('68d6a7a2c17a84ee', 'KY', '["federal"]', 'candidate_eligibility', 'What are the eligibility requirements for U.S. House and Senate candidates in Kentucky?', '["US Senate residency requirements Kentucky","Age to run for Congress in Kentucky","Federal constitutional requirements for KY candidates"]', 'Federal candidates must meet standard U.S. Constitutional requirements: U.S. House members must be at least 25 years old, a U.S. citizen for 7 years, and an inhabitant of the state when elected. U.S. Senators must be at least 30 years old, a U.S. citizen for 9 years, and an inhabitant of the state when elected.', 'https://elect.ky.gov/Candidates/Pages/Qualifications-and-Filing-Fees.aspx', 'Kentucky State Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('e385ea05baa85199', 'KY', '["state"]', 'candidate_eligibility', 'What are the term limits for the Kentucky Governor?', '["How many terms can a Kentucky Governor serve?","Andy Beshear term limits KY","Kentucky executive term limit law"]', 'Under the Kentucky Constitution, the Governor is limited to serving two consecutive four-year terms. After serving two consecutive terms, an individual is ineligible to run for the office again until a full four-year term has intervened.', 'https://ballotpedia.org/Governor_of_Kentucky', 'Kentucky Constitution', '2026-05-17', 'static', 'secondary_source', 'Gubernatorial candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('89ff8aa841a8e91a', 'KY', '["state"]', 'candidate_eligibility', 'Does the Kentucky Attorney General have to be a licensed attorney?', '["Qualifications to run for Attorney General in KY","Do I need to be a member of the bar to be KY AG?","Legal requirements for Kentucky Attorney General"]', 'Yes. The Kentucky Constitution requires that the Attorney General must be a practicing lawyer for at least eight years prior to election. They must also be at least 30 years old and a citizen of Kentucky for at least two years.', 'https://elect.ky.gov/Candidates/Pages/Qualifications-and-Filing-Fees.aspx', 'Kentucky State Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('9db3ab6814713489', 'KY', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Lieutenant Governor in Kentucky?', '["Kentucky Lt Gov requirements","Does the Lt Gov have the same requirements as the Governor in KY?","Qualifications for Lieutenant Governor of Kentucky"]', 'The qualifications for Lieutenant Governor are identical to those for Governor. A candidate must be at least 30 years old and a citizen and resident of Kentucky for at least six years continuously preceding their election.', 'https://elect.ky.gov/Candidates/Pages/Qualifications-and-Filing-Fees.aspx', 'Kentucky State Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Statewide executive candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('72114cf91cb385a7', 'KY', '["county"]', 'candidate_eligibility', 'What are the eligibility requirements for county officeholders in Kentucky?', '["Kentucky county clerk qualifications","Can I run for county judge/executive in KY?","County residency for KY officials"]', 'To run for a typical county office (such as County Clerk or County Judge/Executive), a candidate must be at least 21 years old (24 for Judge/Executive), a citizen of Kentucky, a state resident for two years, and a resident of the county/district for at least one year immediately preceding the election.', 'https://elect.ky.gov/Candidates/Pages/Qualifications-and-Filing-Fees.aspx', 'Kentucky State Board of Elections - Local Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'County candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('bca4da3542c071c3', 'KY', '["federal","state","county","municipal"]', 'voter_interaction', 'Is a photo ID required to vote in person in Kentucky?', '["Kentucky voter ID requirements","Do I need my driver''s license to vote in KY?","Acceptable ID for Kentucky voting"]', 'Yes. Kentucky enforces a photo ID requirement. Voters must present a valid government-issued photo ID (such as a KY driver''s license, U.S. passport, or military ID) at the polls. If a voter lacks a photo ID due to a reasonable impediment, they may cast a regular ballot by signing a ''Reasonable Impediment Record'' and presenting a non-photo document (like a Social Security card or credit card).', 'https://elect.ky.gov/Voters/Pages/Voter-ID.aspx', 'Kentucky State Board of Elections - Voter ID', '2026-05-17', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('82d3a64ca4fd978f', 'KY', '["federal","state","county","municipal"]', 'voter_interaction', 'Is Kentucky a universal mail ballot state, and is no-excuse absentee voting allowed?', '["Do all voters get a mail ballot in Kentucky?","Kentucky vote-by-mail system","Do I need an excuse to vote absentee in KY?"]', 'No. Kentucky is NOT a universal mail ballot state and strictly prohibits no-excuse mail-in absentee voting. A registered voter must satisfy a specific statutory excuse to request a mail-in ballot, such as advanced age (65+), illness, disability, or temporarily residing outside the county (e.g., military, college student).', 'https://elect.ky.gov/Voters/Pages/Absentee-Voting.aspx', 'Kentucky State Board of Elections - Absentee Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('0896479ef8952706', 'KY', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Kentucky offer early in-person voting?', '["Can I vote early in person in KY?","Kentucky early voting dates 2026","When does early voting start in Kentucky?"]', 'Yes. Counter to older baseline assumptions, Kentucky law now allows for true no-excuse early in-person voting. All registered voters may cast a ballot without an excuse on the Thursday, Friday, and Saturday immediately preceding Election Day. Additionally, voters with a valid excuse may utilize excused in-person absentee voting for six business days prior to the start of the no-excuse early voting period.', 'https://elect.ky.gov/Voters/Pages/Absentee-Voting.aspx', 'Kentucky State Board of Elections - Early Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('2f4d127174f0df53', 'KY', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the voter registration deadline and does Kentucky offer same-day registration?', '["Last day to register to vote in KY","Kentucky same day voter registration","Voter registration deadline 2026 Kentucky"]', 'The deadline to register to vote in Kentucky is 29 days prior to the election. Registration can be completed online, by mail, or in person. Kentucky DOES NOT offer same-day voter registration at the polls.', 'https://elect.ky.gov/Voters/Pages/Voter-Registration.aspx', 'Kentucky State Board of Elections - Voter Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('0d30fec0f3f25fda', 'KY', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the electioneering buffer zone distance in Kentucky?', '["How close can I campaign to a polling place in KY?","Kentucky 100 feet electioneering rule","KY buffer zone around voting centers"]', 'Under KRS 117.235, electioneering is strictly prohibited within 100 feet of the entrance to a building in which a voting machine is located. This bans distributing campaign literature, displaying signs, or verbally soliciting votes within this zone.', 'https://apps.legislature.ky.gov/law/statutes/statute.aspx?id=43818', 'Kentucky Revised Statutes 117.235', '2026-05-17', 'static', 'statute_citation', 'Campaign workers and Voters', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('8f93737c8778f88f', 'KY', '["federal","state","county","municipal"]', 'voter_interaction', 'How are voting rights restored for individuals with felony convictions in Kentucky?', '["Can felons vote in Kentucky state?","Felony voting rights restoration KY","Voting on parole in Kentucky"]', 'Kentucky''s constitution mandates that a felony conviction permanently revokes voting rights, which can generally only be restored via executive pardon by the Governor. However, an executive order issued in 2019 proactively restores voting rights to individuals with non-violent felony convictions once they have fully completed their sentences (including probation and parole).', 'https://civilrightsrestoration.ky.gov/', 'Kentucky Department of Corrections - Civil Rights Restoration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('fd0d2926b46db2c5', 'KY', '["county"]', 'voter_interaction', 'How many counties are in Kentucky, and why does it matter for campaigns?', '["Kentucky county election administration","How many county clerks in KY?","Local election control Kentucky"]', 'Kentucky has 120 counties. This highly decentralized structure requires statewide campaigns to coordinate logistics across 120 distinct County Clerks and County Boards of Elections, who administer voting equipment, absentee ballot counting, and early voting sites locally.', 'https://elect.ky.gov/Contact-County-Clerks/Pages/default.aspx', 'Kentucky State Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('f4e232ba64a1a7ef', 'KY', '["federal","state","county","municipal"]', 'voter_interaction', 'How can campaigns access the Kentucky voter file?', '["Kentucky voter database access cost","How to get the voter list in KY","What data is included in the Kentucky voter file?"]', 'Campaigns and political committees can purchase the statewide or county-specific voter registration list directly from the State Board of Elections. The list contains voter names, addresses, demographic data, and voting history, and its use is legally restricted to political, governmental, or scholarly purposes.', 'https://elect.ky.gov/Candidates/Pages/Request-Voter-Registration-Data.aspx', 'Kentucky State Board of Elections - Request Data', '2026-05-17', 'static', 'official_source_direct', 'Campaign Strategists', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('f86c7cdd6591d676', 'KY', '["state","county","municipal"]', 'finance_ethics', 'Which agency administers campaign finance tracking in Kentucky?', '["Where do I file campaign finance reports in KY?","What is the Kentucky Registry of Election Finance?","Does the KY Secretary of State handle campaign finance?"]', 'Campaign finance and disclosure laws in Kentucky are administered exclusively by the Kentucky Registry of Election Finance (KREF). All state and local candidates must register their committees and file their contribution and expenditure reports electronically through the KREF portal.', 'https://kref.ky.gov/', 'Kentucky Registry of Election Finance', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('9bb198c8b3a013e1', 'KY', '["state","county"]', 'finance_ethics', 'What are the individual campaign contribution limits in Kentucky for the 2026 cycle?', '["Are there contribution limits in Kentucky?","KY individual donation caps 2026 election","Maximum donation to state legislature Kentucky"]', 'Kentucky imposes strict contribution limits. For the current cycle, an individual or standard permanent committee (PAC) may contribute a maximum of $2,200 per election to a candidate for statewide or local office. Primary and general elections are considered separate, meaning a donor can give $2,200 for the primary and another $2,200 for the general.', 'https://kref.ky.gov/Pages/Contribution-Limits.aspx', 'Kentucky Registry of Election Finance - Contribution Limits', '2026-05-17', 'per_cycle', 'official_source_direct', 'Candidates and Donors', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('58ef166a3ae8a209', 'KY', '["state","county","municipal"]', 'finance_ethics', 'Are corporate contributions permitted in Kentucky campaigns?', '["Corporate contribution ban Kentucky state","Can a business donate to my campaign in KY?","Corporate campaign finance rules Kentucky"]', 'No. Direct contributions from corporations or LLCs to candidates, slates of candidates, or political party executive committees are strictly PROHIBITED in Kentucky. Corporations may only make contributions by establishing and administering a separate permanent committee (PAC) funded by voluntary employee donations.', 'https://kref.ky.gov/Pages/Contribution-Limits.aspx', 'Kentucky Registry of Election Finance', '2026-05-17', 'static', 'official_source_direct', 'Candidates and Businesses', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('8c82a72689a719d3', 'KY', '["state","county","municipal"]', 'finance_ethics', 'What is the general campaign finance reporting schedule for Kentucky candidates?', '["KREF filing dates 2026","When are campaign finance reports due in KY?","Kentucky pre-primary and pre-general report deadlines"]', 'Active candidate committees must file quarterly reports. During an election year, this expands to include critical pre-election reports due 32 days before the election, 15 days before the election, and a post-election report due 30 days after the election.', 'https://kref.ky.gov/Pages/Reporting-Schedules.aspx', 'Kentucky Registry of Election Finance', '2026-05-17', 'per_cycle', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('ba7b3c290e9c6abe', 'KY', '["state","county","municipal"]', 'finance_ethics', 'What are Kentucky''s rapid disclosure requirements for late contributions?', '["Kentucky 48-hour large contribution report","Late contribution reporting Kentucky KREF","When do I file a rapid report in KY?"]', 'Kentucky requires rapid disclosure for significant last-minute contributions. If a candidate receives a contribution of $500 or more within the 14 days immediately preceding an election, they must report it to KREF electronically within 48 hours of receipt.', 'https://kref.ky.gov/KREF%20Forms%20and%20Pubs/Candidate%20Guide.pdf', 'Kentucky Registry of Election Finance - Candidate Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('25a9078bd5bf8934', 'KY', '["state"]', 'finance_ethics', 'Does Kentucky provide public financing for state campaigns?', '["Public matching funds for Kentucky Governor","State funded campaigns Kentucky status","Government campaign grants KY"]', 'No. Following the repeal of the state''s public financing program (which previously offered matching funds for gubernatorial slates), Kentucky currently provides no system of public financing or matching funds for state-level political campaigns. Candidates must rely entirely on private contributions.', 'https://kref.ky.gov/', 'Kentucky Registry of Election Finance', '2026-05-17', 'static', 'official_source_direct', 'State candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('807209f257b2b3d8', 'KY', '["state","county","municipal"]', 'finance_ethics', 'Are candidates prohibited from using campaign funds for personal use in Kentucky?', '["KY personal use prohibition campaign finance","Can I use campaign money for personal items in KY?","Prohibited expenditures Kentucky KREF"]', 'Yes. Under Kentucky law, campaign funds cannot be converted to personal use. Allowable expenditures must bear a direct relationship to the candidate''s campaign or the ordinary and necessary expenses of holding public office. Unallowable purchases include personal vehicles, clothing, or club memberships.', 'https://kref.ky.gov/KREF%20Forms%20and%20Pubs/Candidate%20Guide.pdf', 'Kentucky Registry of Election Finance - Candidate Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('01bb4195a16b07b3', 'KY', '["state"]', 'finance_ethics', 'Is there a session freeze on campaign contributions for Kentucky legislators?', '["Can Kentucky legislators raise money during session?","Lobbyist contribution ban KY legislature","Legislative session contribution rules Kentucky"]', 'Yes. Kentucky strictly enforces a ''session freeze'' under KRS 6.767. State lawmakers, candidates for the General Assembly, and their campaign committees are prohibited from accepting campaign contributions from a legislative agent (lobbyist) at any time. Furthermore, during a regular session of the General Assembly, they are prohibited from accepting contributions from the employers of lobbyists or from PACs.', 'https://apps.legislature.ky.gov/law/statutes/statute.aspx?id=52209', 'Kentucky Revised Statutes 6.767', '2026-05-17', 'static', 'statute_citation', 'State legislative candidates and Lobbyists', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('d8a383a5571dbc36', 'KY', '["federal","state"]', 'redistricting', 'Who draws Kentucky''s congressional and state legislative maps?', '["Does the KY legislature draw district maps?","Who has the authority to draw district lines in Kentucky?","Kentucky redistricting commission"]', 'In Kentucky, the state legislature holds the exclusive authority to draw and enact both congressional and state legislative district boundaries. The maps are passed as regular legislation and are subject to the Governor''s signature or veto.', 'https://ballotpedia.org/Redistricting_in_Kentucky', 'Ballotpedia - Redistricting in Kentucky', '2026-05-17', 'static', 'secondary_source', 'Federal and State candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('5cbad42e3c205325', 'KY', '["federal","state"]', 'redistricting', 'What are the legal criteria for redistricting in Kentucky?', '["Standards for drawing Kentucky district lines","Kentucky gerrymandering rules","Map requirements KY"]', 'Under the Kentucky Constitution, state legislative districts must be contiguous, and counties cannot be divided to form a district unless required to meet federal equal population standards. Congressional districts must meet federal equal population rules and comply with the Voting Rights Act.', 'https://ballotpedia.org/Redistricting_in_Kentucky', 'Kentucky Constitution', '2026-05-17', 'static', 'statute_citation', 'Federal and State candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('0d31e6e51291856d', 'KY', '["state"]', 'redistricting', 'Are the current Kentucky state legislative maps operative for the 2026 cycle?', '["Status of Kentucky Senate redistricting maps","Are there pending redistricting lawsuits in Kentucky?","Kentucky 2026 state legislative boundaries"]', 'Yes. The redistricting maps enacted in 2022 remain fully operative for the 2026 election cycle. The Kentucky Supreme Court upheld the state legislative maps, ruling that the state constitution does not explicitly forbid partisan gerrymandering.', 'https://www.lrc.ky.gov/', 'Kentucky Legislative Research Commission', '2026-05-17', 'static', 'official_source_direct', 'State legislative candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('1dd38479cc20a49c', 'KY', '["federal"]', 'redistricting', 'What is the status of Kentucky''s congressional map for the 2026 cycle?', '["Is the KY congressional map operative for 2026?","VRA challenges to Kentucky congressional districts","Kentucky congressional redistricting controversy"]', 'The congressional map enacted by the legislature in 2022 remains the operative map for the 2026 election cycle. While the map faced early legal challenges regarding partisan gerrymandering, the Kentucky Supreme Court upheld the map, and there is no active controversy preventing its use.', 'https://elect.ky.gov/', 'Kentucky State Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Federal candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('dc01dde4f74c6e5b', 'KY', '["state"]', 'recall_rules', 'Does Kentucky have a recall mechanism for state officials?', '["Can the Governor of Kentucky be recalled?","How to recall a state senator in KY","Statewide recall election rules Kentucky"]', 'No. The Commonwealth of Kentucky does not have any legal or constitutional mechanism for the recall of state-level elected officials, including the Governor, statewide executives, or members of the state legislature.', 'https://ballotpedia.org/Laws_governing_recall_in_Kentucky', 'Laws governing recall in Kentucky', '2026-05-17', 'static', 'secondary_source', 'Statewide and legislative candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('045340a408a63bfb', 'KY', '["county","municipal"]', 'recall_rules', 'What are the rules for local recall in Kentucky?', '["Kentucky county commissioner recall rules","Signature requirement local recall Kentucky","Recalling a mayor in KY"]', 'Kentucky does not have a general statutory recall process for county or municipal officials. Recall is only permitted in an extremely narrow subset of circumstances or municipalities, meaning the vast majority of local officials cannot be recalled by voters.', 'https://ballotpedia.org/Laws_governing_recall_in_Kentucky', 'Laws governing recall in Kentucky', '2026-05-17', 'static', 'secondary_source', 'Local candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('0b513c63a5580d2a', 'KY', '["state"]', 'ballot_access', 'Does Kentucky have a citizen initiative process?', '["How to get an initiative on the KY ballot","Kentucky citizen initiative signature requirements","Can citizens propose laws in Kentucky?"]', 'No. Kentucky is one of the states that does NOT have a statewide citizen initiative process. Citizens cannot draft statutes or constitutional amendments and gather signatures to place them on the ballot. All statewide ballot measures must be referred by the state legislature.', 'https://ballotpedia.org/Initiative_and_referendum_in_Kentucky', 'Ballotpedia - Initiative and Referendum in Kentucky', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('003ca52739e9e5ae', 'KY', '["state"]', 'ballot_access', 'How does the Kentucky legislature refer a constitutional amendment to the voters?', '["Legislative referral process Kentucky","Referendum by legislature KY","Can the KY legislature put a constitutional amendment on the ballot?"]', 'The Kentucky State Legislature can propose a constitutional amendment by securing a three-fifths (60%) supermajority vote in both the House of Representatives and the State Senate during a single legislative session. The proposed amendment is then referred directly to the voters on the next general election ballot.', 'https://ballotpedia.org/Article_XIV,_Kentucky_Constitution', 'Kentucky Constitution Article XIV', '2026-05-17', 'static', 'statute_citation', 'Legislators and Strategists', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('6410fc9a9283f446', 'KY', '["state"]', 'ballot_access', 'Does Kentucky have a veto referendum process?', '["How to refer a KY bill to the ballot","Kentucky citizen referendum rules","Veto referendum signature threshold Kentucky state"]', 'No. Kentucky does not have a statewide veto referendum process. Citizens cannot gather signatures to suspend and refer an already-passed legislative act to the ballot for a popular vote of approval or rejection.', 'https://ballotpedia.org/Initiative_and_referendum_in_Kentucky', 'Ballotpedia - Initiative and Referendum in Kentucky', '2026-05-17', 'static', 'secondary_source', 'Ballot measure committees', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('41e4fb39a86036eb', 'KY', '["state"]', 'ballot_access', 'What voter approval threshold is required to pass ballot measures in Kentucky?', '["Kentucky ballot measure pass threshold","Does a measure need a supermajority in KY?","Majority vote requirements Kentucky ballot measures"]', 'In Kentucky, a legislatively referred constitutional amendment requires only a simple majority (over 50%) of the total votes cast on that specific measure to pass and become part of the state constitution.', 'https://ballotpedia.org/Article_XIV,_Kentucky_Constitution', 'Kentucky Constitution Article XIV', '2026-05-17', 'static', 'statute_citation', 'Ballot measure committees', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('a8c1719a87164f03', 'KY', '["state"]', 'candidate_eligibility', 'What are the eligibility requirements to run for Secretary of State in Kentucky?', '["Requirements to run for KY Secretary of State","Who can run for Secretary of State in KY?","Residency rules for Kentucky SOS"]', 'Under Section 91 of the Kentucky Constitution, a candidate for Secretary of State must be at least 30 years old at the time of election, a citizen of Kentucky, and a resident of the state for at least two years immediately preceding the election.', 'https://elect.ky.gov/Candidates/Pages/Qualifications-and-Filing-Fees.aspx', 'Kentucky State Board of Elections - Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('26beed338242af94', 'KY', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for State Treasurer in Kentucky?', '["Eligibility for Kentucky State Treasurer","Who can run for State Treasurer in KY?","Kentucky Treasurer residency requirements"]', 'Under Section 91 of the Kentucky Constitution, the qualifications for State Treasurer are identical to those for the Secretary of State: a candidate must be at least 30 years old, a citizen of Kentucky, and a resident of the state for at least two years preceding the election.', 'https://elect.ky.gov/Candidates/Pages/Qualifications-and-Filing-Fees.aspx', 'Kentucky State Board of Elections - Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('0fc25584fbb17b29', 'KY', '["state"]', 'candidate_eligibility', 'Is the Auditor of Public Accounts an elected office in Kentucky, and what are the qualifications?', '["What does the KY Auditor do?","Qualifications for Kentucky Auditor","Is the Auditor elected in KY?"]', 'Yes. The Auditor of Public Accounts is a statewide elected constitutional officer. Under Section 91 of the Kentucky Constitution, candidates must be at least 30 years old, a citizen of Kentucky, and a resident of the state for at least two years preceding the election.', 'https://elect.ky.gov/Candidates/Pages/Qualifications-and-Filing-Fees.aspx', 'Kentucky State Board of Elections - Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('0f5bf789e66c4441', 'KY', '["municipal"]', 'candidate_eligibility', 'What are the eligibility requirements for a school board candidate in Kentucky?', '["Run for school board Kentucky requirements","Who can be a school board member in KY?","School board residency rules Kentucky"]', 'To run for a local school board in Kentucky, candidates must be at least 24 years old, a Kentucky citizen for three years preceding the election, a voter of the district they seek to represent, and must have completed the twelfth grade or hold a GED.', 'https://elect.ky.gov/Candidates/Pages/Qualifications-and-Filing-Fees.aspx', 'Kentucky State Board of Elections - Local Candidate Qualifications', '2026-05-17', 'static', 'official_source_direct', 'School board candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('c2e13c06d25a66f3', 'KY', '["judicial"]', 'candidate_eligibility', 'What are the qualifications for Kentucky Supreme Court justices?', '["Kentucky Supreme Court Justice eligibility","Years of practice required for KY Supreme Court","Are Kentucky judges elected or appointed?"]', 'Kentucky Supreme Court Justices are elected in nonpartisan elections from seven supreme court districts. A candidate must be a citizen of the United States, a resident of their district for two years, and a licensed attorney who has practiced law for at least eight years.', 'https://kycourts.gov/Courts/Supreme-Court/Pages/default.aspx', 'Kentucky Court of Justice', '2026-05-17', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('cde7ff82350fa734', 'KY', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the ballot signature cure process for absentee ballots in Kentucky?', '["How to fix a rejected signature in KY","Kentucky ballot cure process deadline","Missing signature on KY mail ballot"]', 'Kentucky allows voters to cure signature discrepancies on their absentee ballots. If the county board of elections determines a signature does not match, they must make a reasonable effort to contact the voter. The voter has until the close of polls (6:00 p.m.) on Election Day to cure the discrepancy and have the ballot counted.', 'https://elect.ky.gov/Voters/Pages/Absentee-Voting.aspx', 'Kentucky State Board of Elections - Absentee Voting', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('2428597aad9fa071', 'KY', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the deadlines for military and overseas (UOCAVA) voters in Kentucky?', '["When are military ballots due in Kentucky?","UOCAVA return deadline KY","Overseas voting rules Kentucky state"]', 'Under UOCAVA, ballots are transmitted to military and overseas voters at least 45 days before an election. Kentucky provides a secure electronic portal for returning these ballots. If returning by mail or electronically, the ballot must be received by the county clerk no later than 6:00 p.m. local time on Election Day.', 'https://elect.ky.gov/Voters/Pages/Military-and-Overseas-Voters.aspx', 'Kentucky State Board of Elections - UOCAVA', '2026-05-17', 'static', 'official_source_direct', 'UOCAVA voters', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('e73bea4848c4df1c', 'KY', '["federal","state","county","municipal"]', 'voter_interaction', 'When are provisional ballots used in Kentucky?', '["What is a provisional ballot in KY?","Voting without ID Kentucky","When do election workers issue provisional ballots?"]', 'Provisional ballots are issued if a voter''s eligibility is in question (e.g., name not on roster) or if they lack an acceptable photo ID. If a voter casts a provisional ballot due to lack of ID, they have until the Friday following the election to provide valid identification to their county clerk to cure the ballot.', 'https://elect.ky.gov/Voters/Pages/Voter-ID.aspx', 'Kentucky State Board of Elections - Voter ID', '2026-05-17', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('9a4fb1f3d66b0f18', 'KY', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Kentucky have Automatic Voter Registration (AVR) at the DMV?', '["Is registration automatic at the Kentucky DMV?","KY motor voter automatic registration","Do I have to register to vote if I get a KY driver''s license?"]', 'No. Kentucky does not have Automatic Voter Registration (AVR). While the state offers eligible citizens the opportunity to register to vote when applying for a driver''s license (in compliance with federal Motor Voter laws), the process is not automatic; voters must actively opt-in.', 'https://elect.ky.gov/Voters/Pages/Voter-Registration.aspx', 'Kentucky State Board of Elections - Voter Registration', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('fde0272bad327dd1', 'KY', '["federal","state","county","municipal"]', 'voter_interaction', 'Does Kentucky offer Online Voter Registration?', '["Can I register to vote online in KY?","Kentucky electronic voter registration","GoVoteKY online registration portal"]', 'Yes. Eligible Kentucky residents can securely register to vote or update their registration using the State Board of Elections'' GoVoteKY online portal. The deadline to register is 29 days prior to an election.', 'https://vrsws.sos.ky.gov/ovrweb/', 'Kentucky State Board of Elections - GoVoteKY', '2026-05-17', 'static', 'official_source_direct', 'Voters', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('23cb70485b706be5', 'KY', '["federal","state","county","municipal"]', 'voter_interaction', 'How does Kentucky maintain its voter registration lists?', '["KY voter list maintenance rules","How are inactive voters handled in Kentucky?","Kentucky voter roll cleaning process"]', 'Kentucky conducts routine list maintenance using National Change of Address (NCOA) data, death records, and felony conviction records. Voters who do not respond to confirmation notices and fail to vote in two consecutive federal general elections are purged from the rolls.', 'https://elect.ky.gov/', 'Kentucky State Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('c22d9c2eb13c21e0', 'KY', '["federal","state","county","municipal"]', 'voter_interaction', 'What is the deadline to return an absentee ballot in Kentucky?', '["When is the last day to mail my ballot in KY?","Kentucky mail ballot postmark deadline","What time are ballots due in Kentucky?"]', 'Kentucky strictly requires that all absentee mail-in ballots be RECEIVED by the county clerk''s office no later than 6:00 p.m. local time on Election Day. Postmarks are not considered; if the ballot physically arrives after 6:00 p.m. on Election Day, it will not be counted.', 'https://elect.ky.gov/Voters/Pages/Voting-In-Person-and-By-Mail.aspx', 'Kentucky State Board of Elections - Upcoming Election Summary', '2026-05-17', 'static', 'official_source_direct', 'Voters and Campaigns', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('cf014f3ca7a18918', 'KY', '["state","county","municipal"]', 'runoff_rules', 'Is Ranked Choice Voting (RCV) used in Kentucky?', '["Does Kentucky use ranked choice voting?","RCV status in Kentucky 2026","Instant runoff voting KY"]', 'No. Ranked Choice Voting (RCV) is strictly prohibited in Kentucky. During the 2024 legislative session, the Kentucky General Assembly passed House Bill 43, which officially banned the use of Ranked Choice Voting for any local, state, or federal election in the state.', 'https://legislature.ky.gov/', 'Kentucky General Assembly (HB 43)', '2026-05-17', 'static', 'secondary_source', 'All candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('87eeaeae8d17d5b9', 'KY', '["federal","state","county"]', 'runoff_rules', 'How are exact ties broken in Kentucky elections?', '["How are tied elections decided in Kentucky?","Tie-breaker rules Kentucky elections","What happens if a race is tied in KY?"]', 'In the rare event of an exact tie in a Kentucky election, state law dictates that the winner is determined by casting lots (e.g., drawing names from a container or a coin toss). This process is overseen by the relevant election commission or the State Board of Elections.', 'https://apps.legislature.ky.gov/law/statutes/statute.aspx?id=43831', 'Kentucky Revised Statutes', '2026-05-17', 'static', 'secondary_source', 'All candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('4039222be2acba5d', 'KY', '["state","county","municipal"]', 'finance_ethics', 'What disclaimer language is required on Kentucky campaign materials?', '["Kentucky ''Paid for by'' rules","Campaign ad disclaimer requirements KY","Political taglines Kentucky KREF"]', 'The Kentucky Registry of Election Finance requires all printed political materials, broadcast advertisements, and digital ads to clearly display a ''Paid for by'' disclaimer. The disclaimer must identify the candidate, committee, or individual that financed the communication.', 'https://kref.ky.gov/KREF%20Forms%20and%20Pubs/Candidate%20Guide.pdf', 'Kentucky Registry of Election Finance - Candidate Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates and PACs', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('2336ad6d9ae86928', 'KY', '["state","county","municipal"]', 'finance_ethics', 'When does outside spending become prohibited coordination in Kentucky?', '["KY campaign coordination rules","When is a PAC expenditure not independent in Kentucky?","Prohibition on candidate-PAC coordination KY"]', 'An independent expenditure becomes ''coordinated'' if it is made in cooperation, consultation, or concert with, or at the request or suggestion of, a candidate or their committee. Once coordinated, the expenditure is treated as an in-kind contribution and is strictly subject to the $2,200 contribution limit.', 'https://kref.ky.gov/', 'Kentucky Registry of Election Finance', '2026-05-17', 'static', 'official_source_direct', 'All candidates and IECs', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('5ebfd96d6318c51e', 'KY', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for late campaign finance filings in Kentucky?', '["KY KREF late fee","Penalty for missing a Kentucky campaign finance deadline","Registry of Election Finance fine for late filing KY"]', 'The Kentucky Registry of Election Finance (KREF) may levy civil penalties for late reports. The fines escalate based on the type of report and days late, potentially reaching up to $500 per day for critical pre-election reports, capped at specific statutory maximums.', 'https://kref.ky.gov/KREF%20Forms%20and%20Pubs/Candidate%20Guide.pdf', 'Kentucky Registry of Election Finance', '2026-05-17', 'static', 'official_source_direct', 'All candidates and treasurers', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('d8e4ef0b97c79dfb', 'KY', '["state","county","municipal"]', 'finance_ethics', 'When and how must a Kentucky campaign committee terminate?', '["Closing a Kentucky campaign committee","KREF committee termination requirements","Final campaign finance report Kentucky"]', 'A candidate committee may formally terminate when it has achieved a zero cash balance, legally disposed of all unexpended funds, and resolved all outstanding debts or loans. A formal Termination Report must be filed with KREF marking the campaign account as closed.', 'https://kref.ky.gov/KREF%20Forms%20and%20Pubs/Candidate%20Guide.pdf', 'Kentucky Registry of Election Finance', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('e59c086b5d0fe679', 'KY', '["state","county","municipal"]', 'finance_ethics', 'What are the disclosure rules for independent expenditures in Kentucky?', '["KY independent expenditure reporting KREF","Disclosure for KY independent expenditure groups","Reporting thresholds for outside spending Kentucky"]', 'PACs and groups making independent expenditures must file detailed disclosure reports with KREF. If significant independent expenditures are made close to an election, they trigger rapid disclosure requirements to ensure transparency.', 'https://kref.ky.gov/', 'Kentucky Registry of Election Finance', '2026-05-17', 'static', 'official_source_direct', 'Independent groups and PACs', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('46af186c732debca', 'KY', '["state","county","municipal"]', 'finance_ethics', 'How are in-kind contributions valued and reported in Kentucky?', '["Kentucky in-kind contribution valuation rules","Reporting non-monetary donations Kentucky campaign","Fair market value for in-kind gifts KY"]', 'In-kind contributions (donated goods, services, or equipment) must be reported to KREF at their fair market value. Crucially, the value of in-kind contributions counts directly toward the donor''s $2,200 per-election monetary contribution limits.', 'https://kref.ky.gov/KREF%20Forms%20and%20Pubs/Candidate%20Guide.pdf', 'Kentucky Registry of Election Finance - Candidate Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('86bc0c4345cdee88', 'KY', '["state","county","municipal"]', 'finance_ethics', 'Are there limits on a candidate loaning personal funds to their own campaign in Kentucky?', '["Kentucky candidate personal loan limits","Can I pay myself back for a campaign loan in KY?","Reporting candidate loans in KREF"]', 'A candidate may loan or contribute an UNLIMITED amount of their own personal funds to their campaign committee; these funds are not subject to contribution limits. Loans must be properly documented on KREF disclosures and may be repaid from campaign contributions raised during the cycle.', 'https://kref.ky.gov/SiteAssets/Pages/Online-Training/Candidate%27s%20Guide%20to%20Campaign%20Finance.pdf', 'Kentucky Registry of Election Finance - Candidate Guide', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('c38cef18384a0a8a', 'KY', '["state","county","municipal"]', 'finance_ethics', 'What can Kentucky candidates do with unexpended campaign funds?', '["What can I do with leftover campaign money in KY?","KY surplus campaign funds rules","Donating remaining campaign funds Kentucky"]', 'Unexpended campaign funds cannot be converted to personal use. Candidates may retain surplus funds for a future campaign, return them pro-rata to contributors, transfer them to an executive committee of a recognized political party, or donate them to an IRS-recognized tax-exempt charitable organization.', 'https://kref.ky.gov/KREF%20Forms%20and%20Pubs/Candidate%20Guide.pdf', 'Kentucky Registry of Election Finance', '2026-05-17', 'static', 'official_source_direct', 'All candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('4c40e41459fada0e', 'KY', '["state","county"]', 'finance_ethics', 'What are the PAC contribution limits to candidates in Kentucky?', '["KY PAC donation limits to candidates 2026","Political committee vs individual contribution limit Kentucky","Maximum PAC gift to state legislator KY"]', 'In Kentucky, Political Action Committees (PACs) are subject to the EXACT SAME contribution limits as individuals. For the 2025-2026 cycle, a PAC is capped at donating $2,200 per election to a candidate for statewide or legislative office.', 'https://kref.ky.gov/Pages/Contribution-Limits.aspx', 'Kentucky Registry of Election Finance - Limits', '2026-05-17', 'per_cycle', 'official_source_direct', 'State and County candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('e63a42da59f36fcd', 'KY', '["county"]', 'election_dates', 'What are the terms and election cycles for county offices in Kentucky?', '["When are county sheriffs elected in KY?","Kentucky county official term lengths","Are county judge/executives on the 2026 ballot?"]', 'Elected county officials in Kentucky—including County Judge/Executives, County Clerks, and Sheriffs—serve four-year terms. They are elected on the midterm cycle. This means the 2026 ballot will be highly populated with key county executive races.', 'https://elect.ky.gov/Voters/Pages/Election-Calendar.aspx', 'Kentucky State Board of Elections', '2026-05-17', 'per_cycle', 'official_source_direct', 'County candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('3f79f674f44f78c5', 'KY', '["state","county","municipal"]', 'election_dates', 'What is the canvassing and certification timeline for Kentucky elections?', '["When are Kentucky election results official?","KY certification deadline","State Board of Elections meeting Kentucky"]', 'County boards of elections must complete their canvass and transmit certified local results to the Secretary of State shortly after the election. The State Board of Elections subsequently meets to officially certify statewide and federal election returns, typically by the third Monday following the election.', 'https://elect.ky.gov/', 'Kentucky State Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'All candidates and campaigns', 'batch_2026-05-17T17-56-31_kentucky_full_v1'),
  ('d107b95ee3bdd02a', 'KY', '["federal","state"]', 'election_dates', 'When and how are special elections called in Kentucky?', '["Kentucky special election timeline","Who calls a special election to fill a US House vacancy in KY?","Filling a midterm vacancy Kentucky"]', 'Special elections to fill federal or state legislative vacancies are called by a writ of election. The Governor calls special elections for federal and statewide vacancies, while the presiding officer of the respective chamber calls them for state legislative vacancies, ensuring adequate time for qualifying and voting.', 'https://elect.ky.gov/', 'Kentucky State Board of Elections', '2026-05-17', 'static', 'official_source_direct', 'Federal and State candidates', 'batch_2026-05-17T17-56-31_kentucky_full_v1')
